define i64 @test(i64 %x) {
  %rem = urem i64 %x, 4
  %result = call i64 @llvm.ctpop.i64(i64 %rem)
  ret i64 %result
}

define i32 @test(i32 %x) {
  %rem = and i32 %x, 3
  %result = call i32 @llvm.ctpop.i32(i32 %rem)
  ret i32 %result
}

define <4 x i16> @test(<4 x i16> %x) {
  %rem = urem <4 x i16> %x, <i16 4, i16 4, i16 4, i16 4>
  %result = call <4 x i16> @llvm.ctpop.v4i16(<4 x i16> %rem)
  ret <4 x i16> %result
}

define i8 @test(i8 %x) {
  %rem = and i8 %x, 3
  %result = call i8 @llvm.ctpop.i8(i8 %rem)
  ret i8 %result
}

define i128 @test(i128 %x) {
  %rem = urem i128 %x, 8
  %result = call i128 @llvm.ctpop.i128(i128 %rem)
  ret i128 %result
}

define <vscale x 4 x i32> @test(<vscale x 4 x i32> %x) {
  %rem = and <vscale x 4 x i32> %x, shufflevector (<vscale x 4 x i32> insertelement (<vscale x 4 x i32> poison, i32 3, i32 0), <vscale x 4 x i32> poison, <vscale x 4 x i32> zeroinitializer)
  %result = call <vscale x 4 x i32> @llvm.ctpop.nxv4i32(<vscale x 4 x i32> %rem)
  ret <vscale x 4 x i32> %result
}

define i64 @test(i64 %x, i64* %p) {
  %rem = urem i64 %x, 4
  store i64 %rem, i64* %p
  %result = call i64 @llvm.ctpop.i64(i64 %rem)
  ret i64 %result
}

